using UnityEngine;
using System.Text;
public class Script
{
    public static object Main()
    {
        var sb = new StringBuilder();
        var animals = Object.FindObjectsOfType<FL.Gameplay.Modules.BigWorld.AnimalController>();
        foreach (var a in animals)
        {
            sb.AppendLine("NetId=" + a.NetId + " type=" + a.AnimalType + " (1=Dog)");
        }
        return sb.ToString();
    }
}
